import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import MapView from "../components/MapView";
import { annoncesApi, favorisApi, statsApi } from "../services/api";

const BienDetail = () => {
  const { id } = useParams();
  const [annonce, setAnnonce] = useState(null);
  const [stats, setStats] = useState([]);

  useEffect(() => {
    annoncesApi.get(id).then((r) => setAnnonce(r.data));
    statsApi.list().then((r) => setStats(r.data.data || []));
  }, [id]);

  if (!annonce) return <div>Chargement...</div>;

  const zoneStats = stats.find((s) => s.zone === annonce.zone && s.type_bien === annonce.type_bien);

  return (
    <div className="space-y-4 bg-white p-6 rounded-xl shadow">
      <h1 className="text-2xl font-semibold">{annonce.titre}</h1>
      <p>{annonce.type_bien} - {annonce.type_offre} - {annonce.zone}</p>
      <p className="text-primary font-bold">{Number(annonce.prix).toLocaleString()} FCFA</p>
      <p>Prix moyen de la zone: {Number(zoneStats?.prix_moyen_m2 || 0).toLocaleString()} FCFA/m²</p>
      <button className="bg-accent text-white px-3 py-1 rounded" onClick={() => favorisApi.add(id)}>Ajouter aux favoris</button>
      <MapView points={[{ ...annonce, lat: annonce.localisation?.coordinates?.[1], lon: annonce.localisation?.coordinates?.[0] }]} />
    </div>
  );
};

export default BienDetail;
